#include <bits/stdc++.h>
using namespace std;

const int N=210,M=40500,INF=1e8;

int T,n,s,t,bx[N],by[N];
double D;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int d[N],now[N];

double cal(int x,int y){
    return sqrt(1LL*(bx[x]-bx[y])*(bx[x]-bx[y])+1LL*(by[x]-by[y])*(by[x]-by[y]));
}

void add(int x,int y,int z){
	//printf("%d %d %d\n",x,y,z);
    ver[++tot]=y,edge[tot]=z,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(s),d[s]=1,now[s]=head[s];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==t)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==t)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(flow-res,edge[i]));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d",&T);
    while(T--){
        memset(head,0,sizeof(head));
        tot=1;
        scanf("%d%lf",&n,&D);
        s=2*n+1;
        int sl=0;
        for(int i=1,sum,cnt;i<=n;i++){
            scanf("%d%d%d%d",&bx[i],&by[i],&sum,&cnt);
            add(s,i,sum);
            add(i,i+n,cnt);
            sl+=sum;
        }
        for(int i=1;i<=n;i++)
            for(int j=i+1;j<=n;j++)
                if(cal(i,j)<=D)
                    add(i+n,j,INF),add(j+n,i,INF);
        bool flag=1;
        for(t=1;t<=n;t++){
            for(int i=2;i<=tot;i+=2)
                edge[i]=edge[i]+edge[i^1],edge[i^1]=0;
            int max_flow=0,flow;
            while(bfs())
                while(flow=Dinic(s,INF))
                    max_flow+=flow;
            if(max_flow==sl){
                if(!flag)
                    printf(" ");
                printf("%d",t-1);
                flag=0;
            }
        }
        if(flag)
            printf("-1");
        puts("");
    }
    return 0;
}
